settings.custom_liquid:
{% assign is_de = false %}

{% assign host_down = request.host | downcase %}
{% assign path_down = request.path | downcase %}
{% assign language_code = localization.language.iso_code | downcase %}

{% if host_down contains '.de' or path_down contains '/de' or language_code == 'de' %}
  {% assign is_de = true %}
{% endif %}

<section class="lift-collection-hero">
  <div class="lift-collection-hero__inner">

    <div class="lift-collection-hero__badge">
      {% if is_de %}
        SOMMERSALE • BIS ZU 40% SPAREN
      {% else %}
        ZOMERSALE • BESPAAR TOT 40%
      {% endif %}
    </div>

    <h1>
      {% if is_de %}
        Unsere meistverkauften LIFT Sneaker
      {% else %}
        Onze bestverkopende LIFT sneakers
      {% endif %}
    </h1>

    <p class="lift-collection-hero__subtitle">
      {% if is_de %}
        Unsichtbare Erhöhung, bequemer Tragekomfort und bis zu +10 cm größer wirken.
      {% else %}
        Onzichtbare verhoging, dagelijks comfort en tot +10 cm langer lijken.
      {% endif %}
    </p>

    <div class="lift-collection-hero__usps">
      <span>
        ✓ 
        {% if is_de %}
          Wähle +4 / +6 / +8 / +10 cm
        {% else %}
          Kies +4 / +6 / +8 / +10 cm
        {% endif %}
      </span>

      <span>
        ✓ 
        {% if is_de %}
          Unsichtbare Erhöhung
        {% else %}
          Onzichtbare lift
        {% endif %}
      </span>

      <span>
        ✓ 
        {% if is_de %}
          Den ganzen Tag bequem
        {% else %}
          Comfortabel de hele dag
        {% endif %}
      </span>

      <span class="lift-collection-hero__deal">
        ✓ 
        {% if is_de %}
          2. Paar -50%
        {% else %}
          2e paar -50%
        {% endif %}
      </span>
    </div>

  </div>
</section>

<style>
  .lift-collection-hero {
    background: linear-gradient(135deg, #f7f8fb 0%, #ffffff 100%);
    padding: 34px 18px 30px;
    border-bottom: 1px solid #eee;
    margin-bottom: 22px;
  }

  .lift-collection-hero__inner {
    max-width: 980px;
    margin: 0 auto;
    text-align: center;
  }

  .lift-collection-hero__badge {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    background: #000;
    color: #fff !important;
    font-weight: 800;
    font-size: 12px;
    letter-spacing: .08em;
    padding: 8px 14px;
    border-radius: 999px;
    margin-bottom: 14px;
  }

  .lift-collection-hero h1 {
    margin: 0;
    font-size: clamp(30px, 5vw, 52px);
    line-height: 1.03;
    font-weight: 900;
    letter-spacing: -0.04em;
    color: #050505 !important;
  }

  .lift-collection-hero__subtitle {
    margin: 12px auto 0;
    max-width: 650px;
    font-size: clamp(16px, 2.2vw, 20px);
    line-height: 1.4;
    color: #333 !important;
    font-weight: 500;
  }

  .lift-collection-hero__usps {
    margin-top: 20px;
    display: flex;
    flex-wrap: wrap;
    gap: 10px;
    justify-content: center;
  }

  .lift-collection-hero__usps span {
    background: #fff;
    border: 1px solid #e4e4e4;
    box-shadow: 0 4px 14px rgba(0,0,0,.05);
    border-radius: 999px;
    padding: 10px 14px;
    font-size: 14px;
    font-weight: 700;
    color: #111 !important;
  }

  .lift-collection-hero__usps .lift-collection-hero__deal {
    background: #000;
    border-color: #000;
    color: #fff !important;
  }

  @media screen and (max-width: 749px) {
    .lift-collection-hero {
      padding: 16px 12px 8px;
      margin-bottom: 0;
    }

    .lift-collection-hero__badge {
      font-size: 10px;
      padding: 7px 11px;
      margin-bottom: 10px;
      letter-spacing: .06em;
    }

    .lift-collection-hero h1 {
      font-size: 28px;
      line-height: 1.02;
      letter-spacing: -0.05em;
    }

    .lift-collection-hero__subtitle {
      margin-top: 8px;
      font-size: 14.5px;
      line-height: 1.35;
      max-width: 320px;
    }

    .lift-collection-hero__usps {
      margin-top: 14px;
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 7px;
    }

    .lift-collection-hero__usps span {
      border-radius: 12px;
      padding: 8px 7px;
      font-size: 11.5px;
      line-height: 1.25;
      box-shadow: 0 3px 10px rgba(0,0,0,.04);
    }

    .lift-collection-hero__usps span:first-child,
    .lift-collection-hero__usps .lift-collection-hero__deal {
      grid-column: 1 / -1;
    }
  }
</style>

{% assign is_de = false %}

{% assign host_down = request.host | downcase %}
{% assign path_down = request.path | downcase %}
{% assign language_code = localization.language.iso_code | downcase %}

{% if host_down contains '.de' or path_down contains '/de' or language_code == 'de' %}
  {% assign is_de = true %}
{% endif %}

<section class="lift-collection-bottom">
  <div class="lift-collection-bottom__inner">

    <h2>
      {% if is_de %}
        Warum LIFT wählen?
      {% else %}
        Waarom kiezen voor LIFT?
      {% endif %}
    </h2>

    <p>
      {% if is_de %}
        Alle LIFT Modelle sind dafür entwickelt, dir auf eine diskrete und bequeme Weise mehr Körpergröße zu geben. Niemand sieht die Erhöhung – aber du spürst den Unterschied sofort.
      {% else %}
        Elk LIFT model is ontworpen om je op een subtiele en comfortabele manier extra lengte te geven. Niemand ziet de verhoging – maar jij voelt het verschil direct.
      {% endif %}
    </p>

    <div class="lift-collection-bottom__cards">
      <div>
        <strong>
          {% if is_de %}
            Unsichtbare Erhöhung
          {% else %}
            Onzichtbare lift
          {% endif %}
        </strong>
        <span>
          {% if is_de %}
            Die Erhöhung ist in den Schuh integriert und von außen kaum zu sehen.
          {% else %}
            De verhoging zit verwerkt in de schoen en is van buitenaf nauwelijks zichtbaar.
          {% endif %}
        </span>
      </div>

      <div>
        <strong>
          {% if is_de %}
            Wähle deine Höhe
          {% else %}
            Kies je eigen hoogte
          {% endif %}
        </strong>
        <span>
          {% if is_de %}
            Entscheide selbst zwischen +4, +6, +8 oder +10 cm zusätzlicher Höhe.
          {% else %}
            Kies zelf uit +4, +6, +8 of +10 cm extra lengte.
          {% endif %}
        </span>
      </div>

      <div>
        <strong>
          {% if is_de %}
            Bequem für jeden Tag
          {% else %}
            Comfortabel voor elke dag
          {% endif %}
        </strong>
        <span>
          {% if is_de %}
            Gemacht für Alltag, Arbeit, Freizeit und besondere Momente.
          {% else %}
            Gemaakt voor dagelijks gebruik, werk, vrije tijd en speciale momenten.
          {% endif %}
        </span>
      </div>

      <div>
        <strong>
          {% if is_de %}
            Normale Sneaker-Optik
          {% else %}
            Normale sneaker-look
          {% endif %}
        </strong>
        <span>
          {% if is_de %}
            Kein auffälliger Absatz und keine losen Einlegesohlen. Einfach ein moderner Sneaker.
          {% else %}
            Geen opvallende hak en geen losse zooltjes. Gewoon een moderne sneaker.
          {% endif %}
        </span>
      </div>

      <div>
        <strong>
          {% if is_de %}
            Mehr Selbstvertrauen
          {% else %}
            Meer zelfvertrouwen
          {% endif %}
        </strong>
        <span>
          {% if is_de %}
            Wirke sofort größer, ohne dass es offensichtlich ist.
          {% else %}
            Lijk direct langer, zonder dat het duidelijk zichtbaar is.
          {% endif %}
        </span>
      </div>

      <div>
        <strong>
          {% if is_de %}
            2. Paar -50%
          {% else %}
            2e paar -50%
          {% endif %}
        </strong>
        <span>
          {% if is_de %}
            Ideal, wenn du eine zweite Farbe oder ein zusätzliches Paar für später möchtest.
          {% else %}
            Ideaal als je een tweede kleur of extra paar voor later wilt.
          {% endif %}
        </span>
      </div>
    </div>

  </div>
</section>

<style>
  .lift-collection-bottom {
    background: #f7f7f7;
    padding: 44px 18px;
    margin-top: 34px;
  }

  .lift-collection-bottom__inner {
    max-width: 980px;
    margin: 0 auto;
    text-align: center;
  }

  .lift-collection-bottom h2 {
    margin: 0;
    font-size: clamp(26px, 4vw, 40px);
    line-height: 1.1;
    font-weight: 900;
    letter-spacing: -0.03em;
    color: #050505 !important;
  }

  .lift-collection-bottom p {
    max-width: 680px;
    margin: 14px auto 28px;
    color: #333 !important;
    font-size: 16px;
    line-height: 1.55;
    font-weight: 500;
  }

  .lift-collection-bottom__cards {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 16px;
  }

  .lift-collection-bottom__cards div {
    background: #fff;
    border-radius: 18px;
    padding: 22px 18px;
    box-shadow: 0 5px 18px rgba(0,0,0,.06);
    border: 1px solid #eeeeee;
  }

  .lift-collection-bottom__cards strong {
    display: block;
    font-size: 17px;
    font-weight: 900;
    margin-bottom: 8px;
    color: #050505 !important;
  }

  .lift-collection-bottom__cards span {
    display: block;
    font-size: 14px;
    line-height: 1.45;
    color: #444 !important;
    font-weight: 500;
  }

  .lift-collection-bottom__cards div:last-child {
    background: #050505;
    border-color: #050505;
  }

  .lift-collection-bottom__cards div:last-child strong,
  .lift-collection-bottom__cards div:last-child span {
    color: #fff !important;
  }

  @media screen and (max-width: 749px) {
    .lift-collection-bottom {
      padding: 30px 14px;
      margin-top: 22px;
    }

    .lift-collection-bottom p {
      margin-bottom: 22px;
      font-size: 15px;
    }

    .lift-collection-bottom__cards {
      grid-template-columns: 1fr;
      gap: 12px;
    }

    .lift-collection-bottom__cards div {
      padding: 18px 16px;
      border-radius: 16px;
    }
  }
</style>
